// Define the function fixHtmlImageTags
function fixHtmlImageTags(s) {
  let lines = s.split('\n');
  for (let i = 0; i < lines.length; i++) {
    if (lines[i].includes('img')) {
      let alt = lines[i].match(/alt=['"](.*?)['"]/);
      if (alt) {
        lines[i] = lines[i].replace(alt[0], '');
      } else {
        lines[i] = lines[i].replace(/src=['"](.*?)['"]/, ' src="\$1" alt="\$1"');
      }
    }
  }
  return lines.join('');
}

