import re
class Solution:
    def fixHtmlImageTags(self, s: str) -> str:
        lines = s.split('\n');
        for i in range(len(lines)):
            if 'img' in lines[i]:
                alt = re.search(r'alt=['"](.*?)['"]', lines[i]);
                if alt:
                    lines[i] = lines[i].replace(alt.group(0), '');
                else:
                    lines[i] = lines[i].replace(r'src=['"](.*?)['"]', r'src="\1" alt="\1"');
        return '\n'.join(lines);
